import { useEffect, useState } from 'react';
import { getRecentActivities } from '../../api/activityApi';

export default function ActivityPanel() {
  const [activities, setActivities] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetchActivities();
    // Refresh every 30 seconds
    const interval = setInterval(fetchActivities, 30000);
    return () => clearInterval(interval)
  }, []);

  const fetchActivities = async () => {
    try {
      setError(null);
      const res = await getRecentActivities(15, 0);
      setActivities(res.data || []);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to fetch activities');
    } finally {
      setLoading(false);
    }
  };

  const getActivityIcon = (actionType, entityType) => {
    if (actionType === 'CREATE') return '✨';
    if (actionType === 'UPDATE') return '✏️';
    if (actionType === 'DELETE') return '🗑️';
    if (actionType === 'LOGIN') return '🔓';
    if (actionType === 'LOGOUT') return '🔒';
    if (actionType === 'VIEWED') return '👁️';
    if (actionType === 'SENT_EMAIL') return '📧';

    if (entityType === 'VEHICLE') return '🚗';
    if (entityType === 'LEAD') return '👥';
    if (entityType === 'APPOINTMENT') return '📅';
    if (entityType === 'SALE') return '💰';
    if (entityType === 'STAFF') return '👤';
    if (entityType === 'USER') return '👤';
    if (entityType === 'DOCUMENT') return '📄';
    if (entityType === 'NOTIFICATION') return '🔔';

    return '📌';
  };

  const getActivityColor = (actionType) => {
    if (actionType === 'CREATE') return '#10b981';
    if (actionType === 'UPDATE') return '#3b82f6';
    if (actionType === 'DELETE') return '#ef4444';
    if (actionType === 'LOGIN') return '#8b5cf6';
    if (actionType === 'LOGOUT') return '#6b7280';
    return '#6b7280';
  };

  const formatTime = (timestamp) => {
    const date = new Date(timestamp);
    const now = new Date();

    // Same day
    if (date.toDateString() === now.toDateString()) {
      const hours = date.getHours().toString().padStart(2, '0');
      const minutes = date.getMinutes().toString().padStart(2, '0');
      return `${hours}:${minutes} today`;
    }

    // Yesterday
    const yesterday = new Date(now);
    yesterday.setDate(yesterday.getDate() - 1);
    if (date.toDateString() === yesterday.toDateString()) {
      return 'yesterday';
    }

    // Within 7 days
    const daysAgo = Math.floor((now - date) / (1000 * 60 * 60 * 24));
    if (daysAgo < 7) {
      return `${daysAgo}d ago`;
    }

    // Formatted date
    return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
  };

  return (
    <div style={{
      backgroundColor: 'var(--bg-card)',
      borderRadius: '12px',
      border: '1px solid var(--border)',
      padding: '24px',
      boxShadow: '0 4px 12px rgba(0,0,0,0.05)'
    }}>
      {/* Header */}
      <div style={{
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        marginBottom: '20px',
        paddingBottom: '16px',
        borderBottom: '1px solid var(--border)'
      }}>
        <div>
          <h3 style={{
            fontSize: '16px',
            fontWeight: 700,
            color: 'var(--text)',
            margin: 0,
            letterSpacing: '-0.3px'
          }}>
            Recent Activities
          </h3>
          <p style={{
            fontSize: '13px',
            color: 'var(--text-muted)',
            margin: '4px 0 0 0',
            fontWeight: 300
          }}>
            Latest system changes and updates
          </p>
        </div>
        <button
          onClick={fetchActivities}
          disabled={loading}
          style={{
            padding: '8px 12px',
            fontSize: '12px',
            fontWeight: 600,
            backgroundColor: 'var(--bg)',
            color: 'var(--text)',
            border: '1px solid var(--border)',
            borderRadius: '6px',
            cursor: loading ? 'not-allowed' : 'pointer',
            transition: 'all 0.2s',
            opacity: loading ? 0.6 : 1
          }}
          onMouseEnter={(e) => !loading && (e.currentTarget.style.backgroundColor = 'var(--primary-soft)')}
          onMouseLeave={(e) => !loading && (e.currentTarget.style.backgroundColor = 'var(--bg)')}
        >
          {loading ? '⟳' : '↻ Refresh'}
        </button>
      </div>

      {/* Loading State */}
      {loading && !activities.length && (
        <div style={{
          textAlign: 'center',
          padding: '40px 20px',
          color: 'var(--text-muted)'
        }}>
          <div style={{ fontSize: '16px', fontWeight: 500 }}>Loading activities...</div>
        </div>
      )}

      {/* Error State */}
      {error && (
        <div style={{
          padding: '12px 16px',
          backgroundColor: '#fee',
          border: '1px solid #fcc',
          borderRadius: '8px',
          color: '#c33',
          fontSize: '13px',
          fontWeight: 500,
          marginBottom: '16px'
        }}>
          {error}
        </div>
      )}

      {/* Activities List */}
      {!loading && activities.length > 0 ? (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
          {activities.map((activity, idx) => (
            <div
              key={idx}
              style={{
                padding: '12px',
                backgroundColor: 'var(--bg)',
                borderRadius: '8px',
                border: '1px solid var(--border)',
                display: 'flex',
                gap: '12px',
                transition: 'all 0.2s',
                alignItems: 'flex-start'
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.backgroundColor = 'var(--bg-card)';
                e.currentTarget.style.boxShadow = '0 2px 8px rgba(0,0,0,0.05)';
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.backgroundColor = 'var(--bg)';
                e.currentTarget.style.boxShadow = 'none';
              }}
            >
              {/* Icon Circle */}
              <div style={{
                width: '36px',
                height: '36px',
                borderRadius: '50%',
                backgroundColor: getActivityColor(activity.actionType),
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                fontSize: '18px',
                flexShrink: 0,
                opacity: 0.9
              }}>
                {getActivityIcon(activity.actionType, activity.entityType)}
              </div>

              {/* Content */}
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{
                  fontSize: '13px',
                  fontWeight: 600,
                  color: 'var(--text)',
                  marginBottom: '2px',
                  lineHeight: '1.3'
                }}>
                  {activity.title}
                </div>

                <div style={{
                  fontSize: '12px',
                  color: 'var(--text-muted)',
                  marginBottom: '4px',
                  lineHeight: '1.3',
                  fontWeight: 300,
                  wordWrap: 'break-word'
                }}>
                  {activity.description}
                </div>

                <div style={{
                  fontSize: '11px',
                  color: 'var(--text-muted)',
                  display: 'flex',
                  gap: '12px',
                  flexWrap: 'wrap'
                }}>
                  <span>📅 {formatTime(activity.timestamp)}</span>
                  {activity.userName && (
                    <span>👤 {activity.userName}</span>
                  )}
                  {activity.userRole && (
                    <span style={{
                      padding: '0 6px',
                      backgroundColor: 'var(--primary-soft)',
                      color: 'var(--primary)',
                      borderRadius: '4px',
                      fontWeight: 600,
                      textTransform: 'capitalize'
                    }}>
                      {activity.userRole}
                    </span>
                  )}
                </div>

                {/* Changes Preview */}
                {activity.changes && Object.keys(activity.changes).length > 0 && (
                  <div style={{
                    marginTop: '6px',
                    fontSize: '11px',
                    color: 'var(--text-muted)',
                    padding: '6px 8px',
                    backgroundColor: 'var(--bg)',
                    borderRadius: '4px',
                    fontFamily: 'monospace',
                    maxHeight: '60px',
                    overflow: 'hidden'
                  }}>
                    {Object.entries(activity.changes).map(([key, value]) => (
                      <div key={key} style={{ marginBottom: '2px' }}>
                        <span style={{ fontWeight: 600 }}>{key}:</span>{' '}
                        {typeof value === 'object'
                          ? `${value.from} → ${value.to}`
                          : value}
                      </div>
                    ))}
                  </div>
                )}
              </div>

              {/* Status Badge */}
              {activity.status && (
                <div style={{
                  padding: '4px 8px',
                  backgroundColor:
                    activity.status === 'success'
                      ? '#d4edda'
                      : activity.status === 'failed'
                      ? '#f8d7da'
                      : '#fff3cd',
                  color:
                    activity.status === 'success'
                      ? '#155724'
                      : activity.status === 'failed'
                      ? '#721c24'
                      : '#856404',
                  borderRadius: '4px',
                  fontSize: '10px',
                  fontWeight: 700,
                  textTransform: 'uppercase',
                  letterSpacing: '0.3px',
                  whiteSpace: 'nowrap'
                }}>
                  {activity.status}
                </div>
              )}
            </div>
          ))}
        </div>
      ) : !loading ? (
        <div style={{
          textAlign: 'center',
          padding: '40px 20px',
          color: 'var(--text-muted)'
        }}>
          <div style={{ fontSize: '14px' }}>No activities yet</div>
        </div>
      ) : null}

      {/* Footer - View All Link */}
      {activities.length > 0 && (
        <div style={{
          marginTop: '16px',
          paddingTop: '16px',
          borderTop: '1px solid var(--border)',
          textAlign: 'center'
        }}>
          <a href="/admin/activities" style={{
            fontSize: '13px',
            fontWeight: 600,
            color: 'var(--primary)',
            textDecoration: 'none',
            cursor: 'pointer',
            transition: 'opacity 0.2s ease'
          }}
          onMouseEnter={(e) => e.currentTarget.style.opacity = '0.7'}
          onMouseLeave={(e) => e.currentTarget.style.opacity = '1'}>
            View All Activities →
          </a>
        </div>
      )}
    </div>
  );
}
